import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def calculate_adjusted_centrality(customer_pos, unvisited_customers):
        if len(unvisited_customers) < 2:
            return 0
        distances = [np.linalg.norm(np.array(customer_pos) - np.array(other_pos)) for other_pos in unvisited_customers]
